const input = $input.first().json;
const query = input.query || {};
const { search, estado, origen, lead_tipo, limit = 50, offset = 0 } = query;

const searchPattern = search ? `%${search}%` : '%';

const allowedEstados = ['NUEVO', 'FRIO', 'TIBIO', 'CALIENTE'];
const estadoFilter = estado && allowedEstados.includes(estado) ? `estado = '${String(estado).replace(/'/g, "''")}' ` : `estado IN ('NUEVO','FRIO','TIBIO','CALIENTE')`;

const originFilter = origen ? `AND origen = '${String(origen).replace(/'/g, "''")}' ` : '';
const tipoFilter = lead_tipo ? `AND lead_tipo = '${String(lead_tipo).replace(/'/g, "''")}' ` : '';

const whereClause = `(nombre ILIKE '${searchPattern}' OR whatsapp ILIKE '${searchPattern}' OR email ILIKE '${searchPattern}')
AND ${estadoFilter}
${originFilter}
${tipoFilter}`;

const query1 = `SELECT id, nombre, whatsapp, email, estado, nivel, origen, lead_tipo, objetivo, resumen, tags, primera_consulta, ultimo_contacto
FROM leads
WHERE ${whereClause}
ORDER BY ultimo_contacto DESC NULLS LAST
LIMIT ${parseInt(limit)} OFFSET ${parseInt(offset)};`;

const query2 = `SELECT COUNT(*) as total FROM leads WHERE ${whereClause};`;

return [{
  json: {
    query1,
    query2,
    limit: parseInt(limit),
    offset: parseInt(offset)
  }
}];

const listResults = $('postgres_list').all();
const countResults = $('postgres_count').all();
const buildQuery = $('build_query').first().json;

const items = listResults.map(row => row.json);
const total = countResults[0]?.json?.total || 0;

return [{
  json: {
    items,
    total,
    limit: buildQuery.limit,
    offset: buildQuery.offset
  }
}];
